import{_ as e,c as a,o as t,a3 as r}from"./chunks/framework.otVI69x1.js";const _=JSON.parse('{"title":"关于","description":"","frontmatter":{},"headers":[],"relativePath":"guide/1-about.md","filePath":"guide/1-about.md","lastUpdated":1715058948000}'),o={name:"guide/1-about.md"},i=r('<h1 id="关于" tabindex="-1">关于 <a class="header-anchor" href="#关于" aria-label="Permalink to &quot;关于&quot;">​</a></h1><h2 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why&quot;">​</a></h2><p>本项目是对自己工作以来的开发经验的总结，把自己的学习、思考、与其它的小收获融入到这个项目中。</p><p>项目的整体框架使用 Spring Boot，虽然后面自己也知道了其它很多优秀的 Java 框架，但是自己比较熟悉 Spring，就用这个吧，虽然它的缺点太明显了，那也无妨。</p><p>最后，感谢各个开源社区，不分语言，不分国家，不涉政治地理文化。互联网能有今天的发展，离不开各个社区、成员所作的贡献，开源社区太强大啦~</p><p>好啦，大概就说这么多吧！</p><p>那怎么行！再补充点儿，后来想到的：</p><p>这个框架中浪子没有使用很多流行的 lib，很多的工具库都是使用 JDK 标准库或者 Spring、Spring Boot 提供的，有些是自己基于这些封装了一点儿，这样使用时比较方便，业务代码也会干净一些。</p><div class="tip custom-block"><p class="custom-block-title">个人的想法</p><ul><li>一个简单的项目框架，使用什么工具交给使用者自己去选择，这样可以让使用者或者团队选择趁手的工具，效率、正确率等等都会大幅提高！</li><li>越少的 lib 引入可以使得包体积减小（虽然得益于科技的发展这已经不算什么了），也可以减少冲突。</li></ul><p>对于其它的好用的、流行的第三方库的使用权就交给用户选择吧。毕竟 Java 生态极其庞大，好用的类库有很多，根据自己或者团队选择合适的就可以。</p></div><h2 id="feature" tabindex="-1">Feature <a class="header-anchor" href="#feature" aria-label="Permalink to &quot;Feature&quot;">​</a></h2><p>作者整理的很勤快，这里什么都没有留下...</p><h2 id="thanks" tabindex="-1">Thanks <a class="header-anchor" href="#thanks" aria-label="Permalink to &quot;Thanks&quot;">​</a></h2><ul><li><a href="https://jb.gg/OpenSourceSupport" target="_blank" rel="noreferrer">JetBrains</a> 为开源项目提供免费的 IntelliJ IDEA 等 IDE 的授权。<br><img style="width:200px;" src="https://resources.jetbrains.com/storage/products/company/brand/logos/jb_beam.png" alt="JetBrains Logo (Main) logo."></li><li><a href="https://github.com/spring-projects/spring-boot" target="_blank" rel="noreferrer">Spring Boot</a></li><li><a href="https://github.com/babyfish-ct/jimmer" target="_blank" rel="noreferrer">Jimmer</a></li><li><a href="https://gradle.org/" target="_blank" rel="noreferrer">Gradle</a></li><li><a href="https://www.postgresql.org/" target="_blank" rel="noreferrer">Postgresql</a></li><li><a href="https://vitepress.dev/zh/guide/getting-started" target="_blank" rel="noreferrer">VitePress</a></li></ul>',13),l=[i];function s(n,p,h,c,d,u){return t(),a("div",null,l)}const b=e(o,[["render",s]]);export{_ as __pageData,b as default};
